#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using MVZ2.GameContent.Effects;
using MVZ2.Managers;
using PVZEngine;
using PVZEngine.Base;

namespace MVZ2.Metas
{
    public class AlmanacVariableContext
    {
        public MainManager main;
        public string currentDefinitionType;
        public NamespaceID currentDefinitionID;
        public AlmanacMetaEntry currentAlmanacEntry;
        public HashSet<string> callStack = new();

        public AlmanacVariableContext(MainManager main, string currentDefinitionType, NamespaceID currentDefinitionID, AlmanacMetaEntry currentAlmanacEntry)
        {
            this.main = main;
            this.currentDefinitionType = currentDefinitionType;
            this.currentDefinitionID = currentDefinitionID;
            this.currentAlmanacEntry = currentAlmanacEntry;
        }
    }

    public static class AlmanacVariableFunctions
    {
        public static AlmanacVariableContext? context;
        public static object? global(params object[] args)
        {
            if (context == null)
                throw new Exception("No AlmanacVariableContext provided.");
            if (args.Length == 1 && args[0] is string idStr)
            {
                var id = NamespaceID.Parse(idStr, context.main.BuiltinNamespace);
                var variable = context.main.ResourceManager.GetAlmanacGlobalVariable(id);
                if (variable == null)
                    throw new Exception($"Cannot find global almanac variable {idStr}");
                return variable.GetVariableValue(context);
            }
            throw new Exception("Invalid global() usage");
        }
        public static object? local(params object[] args)
        {
            if (context == null)
                throw new Exception("No AlmanacVariableContext provided.");
            if (args.Length == 1 && args[0] is string idStr)
            {
                var variable = context.currentAlmanacEntry.GetLocalVariable(idStr);
                if (variable == null)
                    throw new Exception($"Cannot find local almanac variable {idStr} in entry {context.currentAlmanacEntry.name}");
                return variable.GetVariableValue(context);
            }
            throw new Exception("Invalid global() usage");
        }
        public static object? property(params object[] args)
        {
            if (context == null)
                throw new Exception("No AlmanacVariableContext provided.");
            string key = args[0].ToString();
            var propertyKey = PropertyMapper.ConvertFromName(key);
            if (!propertyKey.IsValid())
                throw new Exception($"Cannot find property of key {key} in variable of almanac entry {context.currentAlmanacEntry.name}.");

            var definitionId = context.currentDefinitionID;
            var definitionType = context.currentDefinitionType;

            if (args.Length >= 2)
            {
                if (args[1] is NamespaceID nid)
                    definitionId = nid;
                else
                    definitionId = NamespaceID.Parse(args[1].ToString(), context.main.BuiltinNamespace);
            }
            if (args.Length >= 3)
            {
                definitionType = args[2].ToString();
            }
            var definition = context.main.Game.GetDefinition<Definition>(definitionType, definitionId);
            if (definition == null)
                throw new Exception($"Cannot find definition {definitionId} of type {definitionType} in variable of almanac entry {context.currentAlmanacEntry.name}.");

            return definition.GetPropertyObject(propertyKey);
        }
        public static bool toBoolean(params object[] args)
        {
            return Convert.ToBoolean(args[0]);
        }
        public static int toShort(params object[] args)
        {
            return Convert.ToInt16(args[0]);
        }
        public static int toInt(params object[] args)
        {
            return Convert.ToInt32(args[0]);
        }
        public static long toLong(params object[] args)
        {
            return Convert.ToInt64(args[0]);
        }
        public static float toFloat(params object[] args)
        {
            return Convert.ToSingle(args[0]);
        }
        public static double toDouble(params object[] args)
        {
            return Convert.ToDouble(args[0]);
        }
        public static NamespaceID? toID(params object[] args)
        {
            if (args[0] is NamespaceID id)
                return id;
            if (context == null)
                return null;
            return NamespaceID.Parse(args[0].ToString(), context.main.BuiltinNamespace);
        }
    }
}
